def orifice_type243(reg):
    suf = reg[-4:]
    if suf == "1Q30":
        return '1-1/4", 30°'
    elif suf == "1Q10":
        return '1-1/4", 10°'
    elif suf == "1030":
        return '1", 30°'
    elif suf == "1010":
        return '1", 10°'
    elif suf == "3430":
        return '3/4", 30°'
    elif suf == "3410":
        return '3/4", 10°'
    elif suf == "1210":
        return '1/2"'
    elif suf == "3810":
        return '3/8"'
    elif suf == "1410":
        return '1/4"'
    elif suf == "2710":
        return '0.207"'

def orifice_max243(reg):
    suf = reg[-4:]
    pre = reg[:6]

    if suf == "1Q30":
        return 15
    elif suf == "1Q10":
        return 25
    elif suf == "1030":
        return 25
    elif suf == "1010":
        return 40
    elif suf == "3430":
        return 40
    elif suf == "3410":
        if pre == "R24312":
            return 60
        else:
            return 40
    elif suf == "1210":
        if pre == "R24312":
            return 100
        else:
            return 80
    elif suf == "3810":
        if pre == "R24312":
            return 125
        else:
            return 100
    elif suf == "1410":
        return 125
    elif suf == "2710":
        return 125

