def gen_match243(result, opp):
    match = None
    is_hp_data = any(k.startswith('R243HP') for k in result)

    if is_hp_data:
        model_labels243 = {
            'R243HP1Q': '243-8HP',
            'R243HP1H': '243-8HP',
            'R243HP20': '243-8HP',
        }
        body_labels243 = {
            'R243HP1Q': '1-1/4"',
            'R243HP1H': '1-1/2"',
            'R243HP02': '2"',
        }
        orifice_order = ['1030', '3410', '1210', '3810', '1410']

        hp_pipe_priority = {
            '1-1/4"': 'R243HP1Q',
            '1-1/2"':  'R243HP1H',
            '2"':    'R243HP02',
        }
        all_prefixes = list(body_labels243.keys())
        prioritized = hp_pipe_priority.get(pipesize_input)
        if prioritized:
            ordered_prefixes = [prioritized] + [p for p in all_prefixes if p != prioritized]
        else:
            ordered_prefixes = all_prefixes
    else:
        model_labels243 = {
            'R243081Q': '243-8',
            'R243081H': '243-8',
            'R2430802': '243-8',
            'R243121Q': '243-12',
            'R243121H': '243-12',
            'R2431202': '243-12',
            'R24312EX': '243-12-1 with External Control Line',
        }
        body_labels243 = {
            'R243081Q': '1-1/4"',
            'R243081H': '1-1/2"',
            'R2430802': '2"',
            'R243121Q': '1-1/4"',
            'R243121H': '1-1/2"',
            'R2431202': '2"',
            'R24312EX': 'Any Size',
        }
        orifice_order = ['1Q10', '1010', '1Q30', '1030', '3430', '3410', '1210', '3810', '1410', '2710']

        std_pipe_priority = {
            '1-1/4"': ['R243081Q', 'R243121Q'],
            '1-1/2"':  ['R243081H', 'R243121H'],
            '2"':    ['R2430802', 'R2431202'],
        }
        all_prefixes = list(body_labels243.keys())
        priority_list = std_pipe_priority.get(pipesize_input, [])
        ordered_prefixes = priority_list + [p for p in all_prefixes if p not in priority_list]


    # monset is the monitor setpoint, will be 0 unless we are sizing for a monitor regulator
    monset = 0
    if opp == "Monitor":
        if outlet_input == 0.25:
            monset = 0.5
        elif outlet_input <= 0.5:
            monset = outlet_input + 0.5
        elif outlet_input < 3:
            monset = outlet_input + 1
        else:
            monset = outlet_input + 2


    # IRV
    if opp == "IRV":
        for prefix in [p for p in ordered_prefixes if p != 'R24312EX']:
            for orifice in orifice_order:
                reg = f"{prefix}_{orifice}"
                if reg in result:
                    cap = result[reg]
                    if will_work(cap, reg, orifice_max243(reg)) == "Yes" and will_irv_work243(reg, opp) != "No":
                        if prefix.startswith('R24308'):
                            color = spring_243_8(outlet_input)['color']
                            range = spring_243_8(outlet_input)['range']
                            model = '243-8-2'
                        else:
                            color = spring_243_12(outlet_input)['color']
                            range = spring_243_12(outlet_input)['range']
                            model = '243-12-2'
                        match = {
                            'reg' : reg,
                            'model': model,
                            'diap': None,
                            'body': body_labels243[prefix],
                            'orifice': orifice_type243(reg),
                            'seat': None,
                            'color': color,
                            'range': range,
                            'capacity': cap,
                            'opp': "IRV",
                            'mon_color': None,
                            'mon_range': None,
                        }
                        return match
    # Other
    else:
        for prefix in ordered_prefixes:
            for orifice in orifice_order:
                reg = f"{prefix}_{orifice}"
                if reg in result:
                    cap = result[reg]
                    if will_work(cap, reg, orifice_max243(reg)) == "Yes":
                        if prefix.startswith('R24308'):
                            color = spring_243_8(outlet_input)['color']
                            range = spring_243_8(outlet_input)['range']
                            model = '243-8-1'
                            mon_color = spring_243_8(monset)['color'] if monset != 0 else None
                            mon_range = spring_243_8(monset)['range'] if monset != 0 else None
                        elif prefix.startswith('R24312') and not prefix.startswith('R24312EX'):
                            color = spring_243_12(outlet_input)['color']
                            range = spring_243_12(outlet_input)['range']
                            model = '243-12-1'
                            mon_color = spring_243_12(monset)['color'] if monset != 0 else None
                            mon_range = spring_243_12(monset)['range'] if monset != 0 else None
                        elif prefix.startswith('R24312EX'):
                            color = spring_243_12(outlet_input)['color']
                            range = spring_243_12(outlet_input)['range']
                            model = '243-12-1 with External Control Line'
                            mon_color = spring_243_12(monset)['color'] if monset != 0 else None
                            mon_range = spring_243_12(monset)['range'] if monset != 0 else None
                        else:
                            color = spring_243hp(outlet_input)['color']
                            range = spring_243hp(outlet_input)['range']
                            model = '243-8HP'
                            mon_color = spring_243hp(monset)['color'] if monset != 0 else None
                            mon_range = spring_243hp(monset)['range'] if monset != 0 else None
                        
                        if opp != "Monitor" or (opp == "Monitor" and mon_color != None):
                            match = {
                                'reg' : reg,
                                'model': model,
                                'diap': None,
                                'body': body_labels243[prefix],
                                'orifice': orifice_type243(reg),
                                'seat': None,
                                'color': color,
                                'range': range,
                                'capacity': cap,
                                'opp': opp,
                                'mon_color': mon_color, # monitor spring color
                                'mon_range': mon_range, # monitor spring range
                            }
                            return match


def run_regulator_selection243(inlet, outlet, opp):
    
    warning = None
    hp_warning = None

    # Correct when user requests IRV but a 243-8HP needs to be used
    if outlet_input > 5 and (opp == "IRV" or opp == "Partial"):
        hp_warning = "243-HP not available with IRV, sized for worker/monitor setup"
        opp = "Monitor"
    elif outlet_input > 4.5 and opp == "IRV":
        hp_warning = "243-8-2 with Cadmium spring only available with partial IRV, sized for worker/monitor setup"
        opp = "Monitor"

    # Select data - standard or hp
    if opp == "Monitor":
        if outlet_input <= 3:
            data_used243 = stddata243
        else:
            data_used243 = hpdata243
    elif opp == "IRV" or opp == "Partial":
        data_used243 = stddata243
    else:
        if outlet_input <= 5:
            data_used243 = stddata243
        else:
            data_used243 = hpdata243


    if opp == "IRV":
        result = interpolate_capacity(data_used243, inlet, outlet, False, False)
        if isinstance(result, str):
            warning = result
            result = None
            match = None
            apply = False
            return result, match, apply, warning

        # Try with IRV
        match = gen_match243(result, opp)

        if match:
            apply = True
            warning = "Sized with IRV"
        # IRV does not work- try with Monitor
        else:

            # Need to change 243 data used to HP data for pressures > 3 psi
            if outlet_input > 3:
                data_used243 = hpdata243
                
            result = interpolate_capacity(data_used243, inlet, outlet, True, False)
            if isinstance(result, str):
                warning = result
                result = None
                match = None
                apply = False
                return result, match, apply, warning

            match = gen_match243(result, "Monitor")

            if match:
                apply = True
                warning = "IRV curves did not work for your application, sized for worker/monitor setup"
            else:
                apply = False      

    # size for monitor
    elif opp == "Monitor":
        result = interpolate_capacity(data_used243, inlet, outlet, True, False)
        if isinstance(result, str):
            warning = result
            result = None
            match = None
            apply = False
            return result, match, apply, warning

        match = gen_match243(result, opp)

        apply = False
        if match:
            apply = True
            if hp_warning != None:
                warning = hp_warning
            else:
                warning = "Sized for worker/monitor setup"

    # no overpressure protection or partial IRV
    else:
        result = interpolate_capacity(data_used243, inlet, outlet, False, False)
        if isinstance(result, str):
            warning = result
            result = None
            match = None
            apply = False
            return result, match, apply, warning

        match = gen_match243(result, opp)

        if match:
            apply = True
        else:
            apply = False
    
    return result, match, apply, warning


